var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"북방합의체 국경 인근 무인지대. 비밀실험구역 G동 특수 격리소, 지하 화물 격납고","JPN":"北方合意体国境近隣の無人地帯。秘密実験区域G棟特殊隔離所、地下貨物格納庫。","ENG":"[[","TWN":"北方和議會邊界附近的無人地帶。秘密實驗區域，G棟，特殊隔離區，地下裝貨車庫。","SCN":"北方联盟边界附近的无人地带。秘密实验区域，G栋，特殊隔离区，地下装货车库。","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"정말 여기까지 와버렸네요.","JPN":"本当にここまで来ちゃいましたね。","ENG":"We've really come this far.","TWN":"真的來到這裡了啊……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"그 레노어라는 사람이 한 말… 믿어도 괜찮은 거겠죠?","JPN":"あのレノアって人の話……信じていいんですよね？","ENG":"What that Lenore person said... Can we trust her?","TWN":"那個叫蕾諾雅的人說的話……可以相信嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그자의 정보는 참고용일 뿐입니다.","JPN":"あの者の情報は参考用に過ぎません。","ENG":"Her information is just for reference.","TWN":"那個人的資訊僅供參考。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리국이 가진 정보와 교차 검증을 거쳐 신뢰성 있는 정보를 추려냈을 뿐이죠.","JPN":"管理局が持っている情報との交差検証を通じて、信頼性のある情報を引き出しただけです。","ENG":"We simply singled out the credible information after cross-referencing her words with the information the Administration has.","TWN":"我們只是透過與管理局所掌握的資訊交叉驗證，篩選出可信的部分。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이제 남은 과제는…","JPN":"あと残りの課題は……","ENG":"Our next task is...","TWN":"現在剩下的任務是……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"예니카 시로코바가 저희의 길 안내를 돕도록 설득하는 것이겠군요.","JPN":"私たちに道案内をするようイェニカ・シロコバを説得するだけでしょうね。","ENG":"to persuade Yanikka Shirokova to be our guide.","TWN":"說服耶妮卡·西羅科娃來為我們引路。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"싫어요! 전 그 장소에 다신 들어가고 싶지 않다고요!","JPN":"イヤです！　私は2度とあの場所に入りたくありません！","ENG":"No! I don't ever want to set foot in that place again!","TWN":"不要！我再也不想去那個地方了！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"시설의 위치도 알려드렸으니 다녀오세요. 전 여기서 얌전히 기다리고 있을게요.","JPN":"施設の位置も教えてあげましたから、行ってきてください。私はここで大人しく待ってますから。","ENG":"I told you where it is, so go without me. I'll be quietly waiting right here.","TWN":"設施的位置也告訴你了，快去吧。我會在這裡乖乖等的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"이 구출 작전에는 내부 구조를 잘 알고 있는 예니카 씨의 도움이 필요해요.","JPN":"この救出作戦には、内部構造をよく知ってるイェニカさんの助けが必要なんですよ。","ENG":"This rescue mission requires your knowledge of the inside, Miss Yanikka.","TWN":"可這次救援行動需要熟悉內部結構的耶妮卡幫助啊……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"그 분을 구하지 못하면, 세상이 멸망할지도 모른다고요.","JPN":"あの方を救出できなかったら、世界が滅亡するかもしれないんですよ。","ENG":"If we don't save her, the world might come to an end.","TWN":"你也聽說了吧，如果不能成功，這個世界可能會滅亡。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"…그렇죠? 사장님?","JPN":"……そうですよね？　社長。","ENG":"...Isn't that right, Boss?","TWN":"……對吧？老闆？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 틀린 말은 아니지.","JPN":"コホン、間違ってはいない。","ENG":"Ahem. You're not wrong.","TWN":"咳，你說的也沒錯。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"세계가… 멸망이요? 그렇게 되면 잭슨 씨도…","JPN":"世界が……滅亡？　そうなるとジャクソンさんも……","ENG":"The world... is going to end? Then, Mr. Jackson will also–","TWN":"世界……毀滅嗎？那樣的話，傑森也會……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아니, 그게 과장이 아니라 진짜라고 해도 말이죠.","JPN":"ううん、それがはったりじゃなくて本当だったとしてもですね。","ENG":"No, even if what you're saying is true and not an exaggeration.","TWN":"不對，就算不是誇張……！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이건 잭슨 씨를 구하는 일이랑 상관 없잖아요! 전 정말 거기 돌아가고 싶지 않단 말이에요!","JPN":"これはジャクソンさんを救うことと関係ないじゃないですか！　私は本当にあそこに戻りたくないんです！","ENG":"This has nothing to do with finding Mr. Jackson! And I really don't want to go back there!","TWN":"這和救傑森無關啊！我真的不想回到那裡！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"안 가, 안 가, 안 가! 안 갈 거야아!","JPN":"行かない、行かない、行かない！　行かないよぉ！","ENG":"I'm not going! Nope! Never in a million years!","TWN":"不去，不去，不去！我才不要去嘛！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"와… 머리가 굴러다니면서 떼쓰고 있어.","JPN":"うわ……頭がゴロゴロしながら駄々こねてる。","ENG":"Wow... She's rolling her head to express her tantrum.","TWN":"哇……只剩腦袋是怎麼做到滾來滾去撒嬌的……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"이렇게 되면 어쩌죠?","JPN":"こうなったらどうしますか？","ENG":"What happens now?","TWN":"這樣的話該怎麼辦呢……？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"쉽지 않겠군. 나도 이런 유형의 사람을 설득해본 적은 없거든.","JPN":"簡単ではなさそうだな。私もこんなタイプの人間を説得したことがない。","ENG":"This isn't easy. I've never convinced someone like her as well.","TWN":"看來不太容易。我也從未試圖說服過這種類型的人。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시로코바.","JPN":"シロコバ。","ENG":"Shirokova.","TWN":"西羅科娃。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이 영상에 나오는 꼬마. 당신이 맞습니까?","JPN":"この映像の子ども。あなたで間違いないですか？","ENG":"Are you the child that appears in this video?","TWN":"影片裡的這個孩子，是你嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"What...?","TWN":"嗯……？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};